/* ═══════════════════════════════════════════════════════════════
   App.tsx – CloudMon Dashboard
   Full drag-and-drop cloud infrastructure editor with animated
   data-flow edges, connection dialogs, instance picker, analysis,
   auto layout, and moveable nodes.
   ═══════════════════════════════════════════════════════════════ */
import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import ReactFlow, {
  addEdge,
  applyNodeChanges,
  applyEdgeChanges,
  Background,
  Connection,
  Controls,
  Edge,
  EdgeChange,
  MiniMap,
  Node,
  NodeChange,
  OnConnect,
  ReactFlowProvider,
  ReactFlowInstance,
  MarkerType,
} from 'react-flow-renderer';
import './App.css';

import {
  ALL_SERVICES,
  ServiceDefinition,
  InstanceType as InstanceDef,
  CATEGORY_COLORS,
} from './serviceCatalog';
import ServiceNode, { ServiceNodeData } from './ServiceNode';
import AnimatedEdge, { ConnectionKind } from './AnimatedEdge';
import Sidebar from './Sidebar';
import Toolbar from './Toolbar';
import ConnectionDialog from './ConnectionDialog';
import InstancePicker from './InstancePicker';
import AnalysisPanel, { AnalysisResult } from './AnalysisPanel';

/* ── helpers ──────────────────────────────────────────────────── */
let _id = 0;
const nextId = () => `svc_${++_id}`;
let _projectId = 0;
const nextProjectId = () => `proj_${++_projectId}`;
let _requestId = 0;
const nextRequestId = () => `req_${++_requestId}`;

type Phase = 'base' | 'request';

interface CanvasState {
  nodes: Node<ServiceNodeData>[];
  edges: Edge[];
}

interface RequestFile {
  id: string;
  name: string;
  canvas: CanvasState;
}

interface Project {
  id: string;
  name: string;
  base: CanvasState;
  requests: RequestFile[];
  activeRequestId: string | null;
}

const emptyCanvas = (): CanvasState => ({ nodes: [], edges: [] });

const cloneNodes = (nodes: Node<ServiceNodeData>[]) =>
  nodes.map((n) => ({ ...n, data: { ...n.data } }));

const cloneEdges = (edges: Edge[]) =>
  edges.map((e) => ({ ...e, data: e.data ? { ...e.data } : e.data }));

const createProject = (name: string): Project => {
  const requestId = nextRequestId();
  return {
    id: nextProjectId(),
    name,
    base: emptyCanvas(),
    requests: [{ id: requestId, name: 'Request 1', canvas: emptyCanvas() }],
    activeRequestId: requestId,
  };
};

const NODE_TYPES = { service: ServiceNode };
const EDGE_TYPES = { animated: AnimatedEdge };

/* ── Flow component ───────────────────────────────────────────── */
function Flow() {
  const wrapperRef = useRef<HTMLDivElement>(null);
  const [rfInstance, setRfInstance] = useState<ReactFlowInstance | null>(null);
  const initialProjectRef = useRef<Project | null>(null);
  if (!initialProjectRef.current) {
    initialProjectRef.current = createProject('Project 1');
  }

  const [projects, setProjects] = useState<Project[]>([initialProjectRef.current]);
  const [activeProjectId, setActiveProjectId] = useState<string>(
    initialProjectRef.current.id
  );
  const [phase, setPhase] = useState<Phase>('base');
  const [activeRequestId, setActiveRequestId] = useState<string>(
    initialProjectRef.current.activeRequestId || ''
  );

  const [nodes, setNodes] = useState<Node<ServiceNodeData>[]>([]);
  const [edges, setEdges] = useState<Edge[]>([]);

  /* sidebar state */
  const [connectionKind, setConnectionKind] = useState<ConnectionKind>('data');

  /* pending connection (waiting for dialog confirmation) */
  const [pendingConn, setPendingConn] = useState<Connection | null>(null);

  /* instance picker state */
  const [pendingDrop, setPendingDrop] = useState<{
    service: ServiceDefinition;
    position: { x: number; y: number };
  } | null>(null);

  /* reconfigure existing node */
  const [reconfigNode, setReconfigNode] = useState<{
    nodeId: string;
    service: ServiceDefinition;
  } | null>(null);

  /* analysis */
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);

  /* ── node & edge change handlers (enables dragging, selecting, removing) */
  const onNodesChange = useCallback(
    (changes: NodeChange[]) => setNodes((nds) => applyNodeChanges(changes, nds)),
    []
  );
  const onEdgesChange = useCallback(
    (changes: EdgeChange[]) => setEdges((eds) => applyEdgeChanges(changes, eds)),
    []
  );

  const activeProject = useMemo(
    () => projects.find((p) => p.id === activeProjectId) || projects[0],
    [projects, activeProjectId]
  );

  const activeRequest = useMemo(() => {
    if (!activeProject) return undefined;
    return (
      activeProject.requests.find((r) => r.id === activeRequestId) ||
      activeProject.requests[0]
    );
  }, [activeProject, activeRequestId]);

  useEffect(() => {
    if (!activeProject) return;
    if (phase === 'base') {
      setNodes(activeProject.base.nodes);
      setEdges(activeProject.base.edges);
      return;
    }

    if (activeRequest) {
      setActiveRequestId(activeRequest.id);
      setNodes(activeRequest.canvas.nodes);
      setEdges(activeRequest.canvas.edges);
    } else {
      setNodes([]);
      setEdges([]);
    }
  }, [activeProjectId, phase]);

  useEffect(() => {
    if (!activeProject) return;
    setProjects((prev) =>
      prev.map((project) => {
        if (project.id !== activeProjectId) return project;
        if (phase === 'base') {
          return { ...project, base: { nodes, edges } };
        }
        const reqId = activeRequestId || project.activeRequestId;
        if (!reqId) return project;
        return {
          ...project,
          activeRequestId: reqId,
          requests: project.requests.map((req) =>
            req.id === reqId ? { ...req, canvas: { nodes, edges } } : req
          ),
        };
      })
    );
  }, [nodes, edges, activeProjectId, phase, activeRequestId, activeProject]);

  /* ── connection handling (opens dialog) ─────────────────────── */
  const onConnect: OnConnect = useCallback(
    (params: Connection) => {
      if (phase === 'base') {
        const edge: Edge = {
          ...params,
          id: `e_${params.source}_${params.target}_${Date.now()}`,
          source: params.source!,
          target: params.target!,
          sourceHandle: params.sourceHandle ?? undefined,
          targetHandle: params.targetHandle ?? undefined,
          type: 'animated',
          markerEnd: { type: MarkerType.ArrowClosed, color: '#888' },
          data: { kind: 'data', label: '', bandwidth: '' },
        };
        setEdges((eds) => addEdge(edge, eds));
        return;
      }
      setPendingConn(params);
    },
    [phase]
  );

  const confirmConnection = useCallback(
    (kind: ConnectionKind, label: string, bandwidth: string) => {
      if (!pendingConn) return;
      const edge: Edge = {
        ...pendingConn,
        id: `e_${pendingConn.source}_${pendingConn.target}_${Date.now()}`,
        source: pendingConn.source!,
        target: pendingConn.target!,
        sourceHandle: pendingConn.sourceHandle ?? undefined,
        targetHandle: pendingConn.targetHandle ?? undefined,
        type: 'animated',
        markerEnd: { type: MarkerType.ArrowClosed, color: '#888' },
        data: { kind, label, bandwidth },
      };
      setEdges((eds) => addEdge(edge, eds));
      setPendingConn(null);
    },
    [pendingConn]
  );

  /* ── helper: create a node from a service + optional instance ── */
  const createNode = useCallback(
    (svc: ServiceDefinition, position: { x: number; y: number }, inst: InstanceDef | null) => {
      const newNode: Node<ServiceNodeData> = {
        id: nextId(),
        type: 'service',
        position,
        dragHandle: '.service-node',          // entire node surface is draggable
        data: {
          serviceId: svc.id,
          label: svc.label,
          icon: svc.icon,
          provider: svc.provider,
          category: svc.category,
          throughput: inst ? inst.throughput : svc.defaultThroughput,
          latency: inst ? inst.latency : svc.defaultLatency,
          instanceTypeId: inst?.id,
          instanceLabel: inst?.label,
          vcpus: inst?.vcpus,
          memoryGb: inst?.memoryGb,
          replicas: 1,
        },
      };
      setNodes((nds) => nds.concat(newNode));
    },
    []
  );

  /* ── drag-and-drop from sidebar ─────────────────────────────── */
  const onDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  }, []);

  const onDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      if (!wrapperRef.current || !rfInstance) return;

      const serviceId = e.dataTransfer.getData('application/cloudmon-service');
      if (!serviceId) return;

      const svc = ALL_SERVICES.find((s) => s.id === serviceId);
      if (!svc) return;

      const bounds = wrapperRef.current.getBoundingClientRect();
      const position = rfInstance.project({
        x: e.clientX - bounds.left,
        y: e.clientY - bounds.top,
      });

      /* if the service has instance types, show picker; otherwise create immediately */
      if (svc.instanceTypes && svc.instanceTypes.length > 0) {
        setPendingDrop({ service: svc, position });
      } else {
        createNode(svc, position, null);
      }
    },
    [rfInstance, createNode]
  );

  const onDragStart = useCallback(
    (e: React.DragEvent<HTMLDivElement>, svc: ServiceDefinition) => {
      e.dataTransfer.setData('application/cloudmon-service', svc.id);
      e.dataTransfer.effectAllowed = 'move';
    },
    []
  );

  /* ── instance picker callbacks ──────────────────────────────── */
  const confirmInstanceDrop = useCallback(
    (inst: InstanceDef | null) => {
      if (!pendingDrop) return;
      createNode(pendingDrop.service, pendingDrop.position, inst);
      setPendingDrop(null);
    },
    [pendingDrop, createNode]
  );

  const confirmReconfig = useCallback(
    (inst: InstanceDef | null) => {
      if (!reconfigNode) return;
      const svc = reconfigNode.service;
      setNodes((nds) =>
        nds.map((n) => {
          if (n.id !== reconfigNode.nodeId) return n;
          return {
            ...n,
            data: {
              ...n.data,
              throughput: inst ? inst.throughput : svc.defaultThroughput,
              latency: inst ? inst.latency : svc.defaultLatency,
              instanceTypeId: inst?.id,
              instanceLabel: inst?.label,
              vcpus: inst?.vcpus,
              memoryGb: inst?.memoryGb,
              replicas: (n.data as ServiceNodeData).replicas ?? 1,
            },
          };
        })
      );
      setReconfigNode(null);
    },
    [reconfigNode]
  );

  /* ── double-click node to reconfigure instance ──────────────── */
  const onNodeDoubleClick = useCallback(
    (_event: React.MouseEvent, node: Node<ServiceNodeData>) => {
      const svc = ALL_SERVICES.find((s) => s.id === node.data.serviceId);
      if (svc && svc.instanceTypes && svc.instanceTypes.length > 0) {
        setReconfigNode({ nodeId: node.id, service: svc });
      }
    },
    []
  );

  /* ── delete selected nodes/edges via Backspace/Delete ────────── */
  const onKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Backspace' || e.key === 'Delete') {
        setNodes((nds) => nds.filter((n) => !n.selected));
        setEdges((eds) => eds.filter((ed) => !ed.selected));
      }
    },
    []
  );

  /* ── toolbar actions ────────────────────────────────────────── */
  const clearCanvas = useCallback(() => {
    setNodes([]);
    setEdges([]);
    setAnalysis(null);
  }, []);

  const autoLayout = useCallback(() => {
    const cols = 4;
    const gapX = 220;
    const gapY = 200;
    setNodes((nds) =>
      nds.map((n, i) => ({
        ...n,
        position: {
          x: 40 + (i % cols) * gapX,
          y: 40 + Math.floor(i / cols) * gapY,
        },
      }))
    );
    setTimeout(() => rfInstance?.fitView(), 50);
  }, [rfInstance]);

  /* ── project + phase actions ───────────────────────────────── */
  const addProject = useCallback(() => {
    const project = createProject(`Project ${projects.length + 1}`);
    setProjects((prev) => prev.concat(project));
    setActiveProjectId(project.id);
    setActiveRequestId(project.activeRequestId || '');
    setPhase('base');
    setNodes(project.base.nodes);
    setEdges(project.base.edges);
    setAnalysis(null);
  }, [projects.length]);

  const renameProject = useCallback(
    (name: string) => {
      setProjects((prev) =>
        prev.map((p) => (p.id === activeProjectId ? { ...p, name } : p))
      );
    },
    [activeProjectId]
  );

  const selectProject = useCallback(
    (id: string) => {
      setActiveProjectId(id);
      setPhase('base');
      setAnalysis(null);
    },
    []
  );

  const addRequest = useCallback(() => {
    if (!activeProject) return;
    const requestId = nextRequestId();
    const nextRequest: RequestFile = {
      id: requestId,
      name: `Request ${activeProject.requests.length + 1}`,
      canvas: emptyCanvas(),
    };
    setProjects((prev) =>
      prev.map((p) =>
        p.id === activeProject.id
          ? {
              ...p,
              requests: p.requests.concat(nextRequest),
              activeRequestId: requestId,
            }
          : p
      )
    );
    setActiveRequestId(requestId);
    setPhase('request');
    setNodes([]);
    setEdges([]);
    setAnalysis(null);
  }, [activeProject]);

  const duplicateRequest = useCallback(() => {
    if (!activeProject || !activeRequest) return;
    const requestId = nextRequestId();
    const nextRequest: RequestFile = {
      id: requestId,
      name: `${activeRequest.name} Copy`,
      canvas: {
        nodes: cloneNodes(activeRequest.canvas.nodes),
        edges: cloneEdges(activeRequest.canvas.edges),
      },
    };
    setProjects((prev) =>
      prev.map((p) =>
        p.id === activeProject.id
          ? {
              ...p,
              requests: p.requests.concat(nextRequest),
              activeRequestId: requestId,
            }
          : p
      )
    );
    setActiveRequestId(requestId);
    setPhase('request');
    setNodes(nextRequest.canvas.nodes);
    setEdges(nextRequest.canvas.edges);
    setAnalysis(null);
  }, [activeProject, activeRequest]);

  const duplicateBaseToRequest = useCallback(() => {
    if (!activeProject || !activeRequest) return;
    const baseCanvas = {
      nodes: cloneNodes(activeProject.base.nodes),
      edges: cloneEdges(activeProject.base.edges),
    };
    setProjects((prev) =>
      prev.map((p) => {
        if (p.id !== activeProject.id) return p;
        return {
          ...p,
          requests: p.requests.map((req) =>
            req.id === activeRequest.id ? { ...req, canvas: baseCanvas } : req
          ),
        };
      })
    );
    setNodes(baseCanvas.nodes);
    setEdges(baseCanvas.edges);
    setAnalysis(null);
  }, [activeProject, activeRequest]);

  const renameRequest = useCallback(
    (name: string) => {
      if (!activeProject || !activeRequest) return;
      setProjects((prev) =>
        prev.map((p) =>
          p.id === activeProject.id
            ? {
                ...p,
                requests: p.requests.map((req) =>
                  req.id === activeRequest.id ? { ...req, name } : req
                ),
              }
            : p
        )
      );
    },
    [activeProject, activeRequest]
  );

  const selectRequest = useCallback(
    (requestId: string) => {
      if (!activeProject) return;
      const request = activeProject.requests.find((r) => r.id === requestId);
      if (!request) return;
      setActiveRequestId(requestId);
      setPhase('request');
      setNodes(request.canvas.nodes);
      setEdges(request.canvas.edges);
      setAnalysis(null);
    },
    [activeProject]
  );

  const runAnalysis = useCallback(() => {
    const nodeMap = new Map(nodes.map((n) => [n.id, n]));
    const targetIds = new Set(edges.map((e) => e.target));
    const sourceNodes = nodes.filter((n) => !targetIds.has(n.id));

    const adj = new Map<string, string[]>();
    for (const e of edges) {
      const list = adj.get(e.source) || [];
      list.push(e.target);
      adj.set(e.source, list);
    }

    const flowPaths: { path: string[]; latency: number }[] = [];
    const visited = new Set<string>();

    function dfs(nodeId: string, path: string[], latency: number) {
      const node = nodeMap.get(nodeId);
      if (!node) return;
      const d = node.data as ServiceNodeData;
      const name = d.instanceLabel ? `${d.label} (${d.instanceLabel})` : d.label;
      const newPath = [...path, name];
      const newLatency = latency + (d.latency || 0);
      const neighbours = adj.get(nodeId) || [];
      if (neighbours.length === 0) {
        flowPaths.push({ path: newPath, latency: newLatency });
      } else {
        for (const nb of neighbours) {
          if (!visited.has(nb)) {
            visited.add(nb);
            dfs(nb, newPath, newLatency);
            visited.delete(nb);
          }
        }
      }
    }

    for (const src of sourceNodes.length ? sourceNodes : nodes.slice(0, 1)) {
      visited.add(src.id);
      dfs(src.id, [], 0);
      visited.delete(src.id);
    }

    let minTp = Infinity;
    let bottleneck: { nodeId: string; label: string; reason: string } | null = null;
    for (const n of nodes) {
      const d = n.data as ServiceNodeData;
      if (d.throughput < minTp) {
        minTp = d.throughput;
        const name = d.instanceLabel ? `${d.label} (${d.instanceLabel})` : d.label;
        bottleneck = {
          nodeId: n.id,
          label: name,
          reason: `Lowest throughput in cluster (${d.throughput.toLocaleString()} req/s)`,
        };
      }
    }

    const totalThroughput = nodes.reduce(
      (s, n) => Math.min(s, (n.data as ServiceNodeData).throughput),
      Infinity
    );

    const maxPathLatency = flowPaths.reduce((m, fp) => Math.max(m, fp.latency), 0);

    setAnalysis({
      nodes: nodes.length,
      edges: edges.length,
      totalThroughput: totalThroughput === Infinity ? 0 : totalThroughput,
      totalLatency: maxPathLatency,
      bottlenecks: bottleneck ? [bottleneck] : [],
      flowPaths: flowPaths.slice(0, 10),
    });
  }, [nodes, edges]);

  /* ── minimap colour helper ──────────────────────────────────── */
  const minimapColor = useCallback((node: Node) => {
    const cat = (node.data as ServiceNodeData)?.category;
    return cat ? CATEGORY_COLORS[cat] || '#555' : '#555';
  }, []);

  /* ── render ─────────────────────────────────────────────────── */
  const nodeTypes = useMemo(() => NODE_TYPES, []);
  const edgeTypes = useMemo(() => EDGE_TYPES, []);

  return (
    <div className="dndflow" onKeyDown={onKeyDown} tabIndex={0}>
      <Sidebar
        onDragStart={onDragStart}
        connectionKind={connectionKind}
        onConnectionKindChange={setConnectionKind}
        showConnectionPicker={phase === 'request'}
      />

      <div className="reactflow-wrapper" ref={wrapperRef}>
        <div className="project-bar">
          <div className="project-left">
            <span className="project-label">Project</span>
            <select
              className="project-select"
              value={activeProject?.id}
              onChange={(e) => selectProject(e.target.value)}
            >
              {projects.map((p) => (
                <option key={p.id} value={p.id}>
                  {p.name}
                </option>
              ))}
            </select>
            <button className="tb-btn" onClick={addProject}>
              + New
            </button>
          </div>
          <div className="project-right">
            <input
              className="project-name-input"
              value={activeProject?.name || ''}
              onChange={(e) => renameProject(e.target.value)}
              placeholder="Project name"
            />
          </div>
        </div>

        <div className="phase-bar">
          <div className="phase-tabs">
            <button
              className={`phase-tab ${phase === 'base' ? 'active' : ''}`}
              onClick={() => setPhase('base')}
            >
              Base Architecture
            </button>
            <button
              className={`phase-tab ${phase === 'request' ? 'active' : ''}`}
              onClick={() => setPhase('request')}
            >
              Request Flows
            </button>
          </div>

          {phase === 'request' && (
            <div className="request-controls">
              <div className="request-tabs">
                {activeProject?.requests.map((req) => (
                  <button
                    key={req.id}
                    className={`request-tab ${req.id === activeRequest?.id ? 'active' : ''}`}
                    onClick={() => selectRequest(req.id)}
                  >
                    {req.name}
                  </button>
                ))}
                <button className="request-add" onClick={addRequest}>
                  + Request
                </button>
              </div>
              <div className="request-actions">
                <input
                  className="request-name-input"
                  value={activeRequest?.name || ''}
                  onChange={(e) => renameRequest(e.target.value)}
                  placeholder="Rename request"
                />
                <button className="tb-btn" onClick={duplicateRequest}>
                  Duplicate
                </button>
                <button className="tb-btn" onClick={duplicateBaseToRequest}>
                  Copy Base
                </button>
              </div>
            </div>
          )}
        </div>

        <Toolbar
          nodeCount={nodes.length}
          edgeCount={edges.length}
          onClear={clearCanvas}
          onAutoLayout={autoLayout}
          onAnalyze={runAnalysis}
        />

        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
          onInit={setRfInstance}
          onDrop={onDrop}
          onDragOver={onDragOver}
          onNodeDoubleClick={onNodeDoubleClick}
          nodeTypes={nodeTypes}
          edgeTypes={edgeTypes}
          defaultEdgeOptions={{
            type: 'animated',
            markerEnd: { type: MarkerType.ArrowClosed, color: '#888' },
          }}
          fitView
          deleteKeyCode={null}
          snapToGrid
          snapGrid={[15, 15]}
          connectionMode={'loose' as any}
        >
          <Background color="#2e3140" gap={20} />
          <Controls />
          <MiniMap nodeColor={minimapColor} maskColor="rgba(0,0,0,0.7)" />
        </ReactFlow>

        <AnalysisPanel result={analysis} onClose={() => setAnalysis(null)} />
      </div>

      {/* Connection dialog */}
      {pendingConn && (
        <ConnectionDialog
          defaultKind={connectionKind}
          onConfirm={confirmConnection}
          onCancel={() => setPendingConn(null)}
        />
      )}

      {/* Instance picker on new drop */}
      {pendingDrop && (
        <InstancePicker
          service={pendingDrop.service}
          onConfirm={confirmInstanceDrop}
          onCancel={() => setPendingDrop(null)}
        />
      )}

      {/* Instance picker on reconfigure (double-click) */}
      {reconfigNode && (
        <InstancePicker
          service={reconfigNode.service}
          onConfirm={confirmReconfig}
          onCancel={() => setReconfigNode(null)}
        />
      )}
    </div>
  );
}

/* ── Root App ─────────────────────────────────────────────────── */
function App() {
  return (
    <div className="App">
      <ReactFlowProvider>
        <Flow />
      </ReactFlowProvider>
    </div>
  );
}

export default App;
